            player.bullets.push({
                x: player.x + player.width / 2,
                y: player.y,
                radius: 3,
                speed: PLAYER_BULLET_SPEED
            });
            player.cooldown = player.maxCooldown;
        }

        function updatePlayerBullets() {
            for (let i = player.bullets.length - 1; i >= 0; i--) {
                player.bullets[i].y -= player.bullets[i].speed;
                if (player.bullets[i].y < 0) {
                    player.bullets.splice(i, 1);
                }
            }
        }

        function updateEnemies() {
            enemySpawnTimer++;
            if (enemySpawnTimer >= ENEMY_SPAWN_INTERVAL && enemies.length < MAX_ENEMIES) {
                enemies.push({
                    x: Math.random() * (canvas.width - 40),
                    y: -40, // 从屏幕上方生成
                    width: 40,
                    height: 40,
                    speed: Math.random() * 1.5 + 0.5,
                    bulletCooldown: Math.floor(Math.random() * 120) + 60, // 敌人射击间隔
                    currentBulletCooldown: 0
                });
                enemySpawnTimer = 0;
            }

            for (let i = enemies.length - 1; i >= 0; i--) {
                const enemy = enemies[i];
                enemy.y += enemy.speed;

                // 敌人射击
                enemy.currentBulletCooldown++;
                if (enemy.currentBulletCooldown >= enemy.bulletCooldown) {
                    enemyBullets.push({
                        x: enemy.x + enemy.width / 2,
                        y: enemy.y + enemy.height,
                        radius: 3,
                        speed: ENEMY_BULLET_SPEED
                    });
                    enemy.currentBulletCooldown = 0;
                    enemy.bulletCooldown = Math.floor(Math.random() * 120) + 60; // 重置冷却
                }

                if (enemy.y > canvas.height) {
                    enemies.splice(i, 1);
                    lives--; // 敌人逃逸扣除生命
                    if (lives <= 0) {
                        gameOver();
                    }
                }
            }
        }

        function updateEnemyBullets() {
            for (let i = enemyBullets.length - 1; i >= 0; i--) {
                enemyBullets[i].y += enemyBullets[i].speed;
                if (enemyBullets[i].y > canvas.height) {
                    enemyBullets.splice(i, 1);
                }
            }
        }

        function updateStars() {
            stars.forEach(star => {
                star.y += star.speed;
                if (star.y > canvas.height) {
                    star.y = 0;
                    star.x = Math.random() * canvas.width;
                }
            });
        }

        // 碰撞检测 AABB
        function checkCollision(rect1, rect2) {
            return rect1.x < rect2.x + rect2.width &&
                   rect1.x + rect1.width > rect2.x &&
                   rect1.y < rect2.y + rect2.height &&
                   rect1.y + rect1.height > rect2.y;
        }

        // 碰撞检测 圆和矩形
        function checkCircleRectCollision(circle, rect) {
            // 找到矩形上距离圆心最近的点
            let testX = circle.x;
            let testY = circle.y;

            if (circle.x < rect.x) testX = rect.x;
            else if (circle.x > rect.x + rect.width) testX = rect.x + rect.width;

            if (circle.y < rect.y) testY = rect.y;
            else if (circle.y > rect.y + rect.height) testY = rect.y + rect.height;

            // 计算最近点和圆心之间的距离
            let distX = circle.x - testX;
            let distY = circle.y - testY;
            let distance = Math.sqrt((distX * distX) + (distY * distY));

            // 如果距离小于圆的半径，则发生碰撞
            return distance <= circle.radius;
        }


        function handleCollisions() {
            // 玩家子弹与敌人
            for (let i = player.bullets.length - 1; i >= 0; i--) {
                for (let j = enemies.length - 1; j >= 0; j--) {
                    if (checkCircleRectCollision(player.bullets[i], enemies[j])) {
                        player.bullets.splice(i, 1);
                        enemies.splice(j, 1);
                        score += 10;
                        break; // 子弹击中一个敌人后消失，所以跳出内层循环
                    }
                }
            }

            // 敌人子弹与玩家
            for (let i = enemyBullets.length - 1; i >= 0; i--) {
                if (checkCircleRectCollision(enemyBullets[i], player)) {
                    enemyBullets.splice(i, 1);
                    lives--;
                    if (lives <= 0) {
                        gameOver();
                    }
                    break;
                }
            }

            // 敌人与玩家
            for (let i = enemies.length - 1; i >= 0; i--) {
                if (checkCollision(player, enemies[i])) {
                    enemies.splice(i, 1); // 敌人被摧毁
                    lives--;
                    if (lives <= 0) {
                        gameOver();
                    }
                    break;
                }
            }
        }

        // 游戏循环
        function gameLoop(currentTime) {
            if (!gameRunning) return;

            const deltaTime = currentTime - lastUpdateTime;

            if (deltaTime > frameInterval) {
                lastUpdateTime = currentTime - (deltaTime % frameInterval);

                // 清除画布
                ctx.clearRect(0, 0, canvas.width, canvas.height);

                // 更新
                updateStars();
                updatePlayer();
                updatePlayerBullets();
                updateEnemies();
                updateEnemyBullets();
                handleCollisions();

                // 绘制
                drawStars();
                drawPlayer();
                drawBullets(player.bullets, playerBulletColor);
                drawEnemies();
                drawBullets(enemyBullets, enemyBulletColor);
                drawScore();
                drawLives();
            }

            requestAnimationFrame(gameLoop);
        }

        function startGame() {
            document.getElementById('start-screen').style.display = 'none';
            document.getElementById('game-over-screen').style.display = 'none';
            resetGame();
            gameRunning = true;
            lastUpdateTime = performance.now();
            requestAnimationFrame(gameLoop);
        }

        function gameOver() {
            gameRunning = false;
            document.getElementById('finalScore').textContent = score;
            document.getElementById('game-over-screen').style.display = 'flex';
        }

        function resetGame() {
            score = 0;
            lives = PLAYER_LIVES;
            player.x = canvas.width / 2 - 25;
            player.y = canvas.height - 70;
            player.bullets = [];
            player.cooldown = 0;
            enemies.length = 0;
            enemyBullets.length = 0;
            enemySpawnTimer = 0;
            stars.length = 0; // 重新初始化星星
            initStars();
        }

        // 事件监听器
        document.getElementById('startButton').addEventListener('click', startGame);
        document.getElementById('restartButton').addEventListener('click', startGame);

        // 初始化游戏
        initStars();
    </script>
</body>
</html>
